import{_ as a,o as e,c as i,a2 as t}from"./chunks/framework.CZqXuAiL.js";const k=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/getting-started/quick-start.md","filePath":"openshield-xdp/getting-started/quick-start.md","lastUpdated":1782454750000}'),n={name:"openshield-xdp/getting-started/quick-start.md"};function o(l,s,d,h,p,r){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><h2 id="load" tabindex="-1">Load <a class="header-anchor" href="#load" aria-label="Permalink to &quot;Load&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openshield</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> load</span></span></code></pre></div><p>This starts the full TUI dashboard. A 10-second safety confirmation appears — press <code>Enter</code> while your SSH session is still accessible to confirm the program stays loaded. If SSH was blocked by a bad config, the program auto-unloads, restoring access.</p><h2 id="daemon-mode" tabindex="-1">Daemon mode <a class="header-anchor" href="#daemon-mode" aria-label="Permalink to &quot;Daemon mode&quot;">​</a></h2><p>For production (systemd):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openshield</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> load</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --stats-off</span></span></code></pre></div><p>No TUI, no safety prompt. The installed systemd service uses this mode:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openshield-loader</span></span></code></pre></div><h2 id="verify" tabindex="-1">Verify <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;Verify&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openshield</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><details class="details custom-block"><summary>Expected output</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OpenShield-XDP Status</span></span>
<span class="line"><span>=====================</span></span>
<span class="line"><span>  XDP Program:  LOADED</span></span>
<span class="line"><span>  Loader:       RUNNING</span></span>
<span class="line"><span>  Telemetry:    AVAILABLE</span></span>
<span class="line"><span>  Interface:    eno1</span></span>
<span class="line"><span>  XDP Mode:     native</span></span></code></pre></div></details><h2 id="common-problems" tabindex="-1">Common problems <a class="header-anchor" href="#common-problems" aria-label="Permalink to &quot;Common problems&quot;">​</a></h2><h3 id="error-failed-to-load-bpf-program" tabindex="-1">&quot;Error: failed to load BPF program&quot; <a class="header-anchor" href="#error-failed-to-load-bpf-program" aria-label="Permalink to &quot;&quot;Error: failed to load BPF program&quot;&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openshield</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fix</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openshield</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> load</span></span></code></pre></div><p>Stale BPF pins from a previous installation are the most common cause.</p><h3 id="tui-stuck-at-loading" tabindex="-1">TUI stuck at &quot;Loading...&quot; <a class="header-anchor" href="#tui-stuck-at-loading" aria-label="Permalink to &quot;TUI stuck at &quot;Loading...&quot;&quot;">​</a></h3><p>The loader process isn&#39;t running. Start it:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openshield</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> load</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --stats-off</span></span></code></pre></div><h3 id="another-loader-instance-is-running" tabindex="-1">&quot;Another loader instance is running&quot; <a class="header-anchor" href="#another-loader-instance-is-running" aria-label="Permalink to &quot;&quot;Another loader instance is running&quot;&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openshield</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unload</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openshield</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> load</span></span></code></pre></div><h2 id="cli-modes" tabindex="-1">CLI modes <a class="header-anchor" href="#cli-modes" aria-label="Permalink to &quot;CLI modes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Use case</th></tr></thead><tbody><tr><td><code>openshield load</code></td><td>Interactive TUI dashboard</td></tr><tr><td><code>openshield load --stats-off</code></td><td>Systemd daemon mode</td></tr><tr><td><code>openshield load --stats-minimal</code></td><td>Text-based snapshots</td></tr><tr><td><code>openshield load -t 3600</code></td><td>Auto-unload after 1 hour</td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/pingless-studios-docs/openshield-xdp/user-guide/configuration">Configuration Reference</a></li><li><a href="/pingless-studios-docs/openshield-xdp/user-guide/tui">TUI Guide</a></li><li><a href="/pingless-studios-docs/openshield-xdp/reference/cli">CLI Reference</a></li></ul>`,25)])])}const u=a(n,[["render",o]]);export{k as __pageData,u as default};
